{
  "sentences": [
    {
      "text": "今天天氣很熱，我心情不好。",
      "pinyin": "Jīntiān tiānqì hěn rè, wǒ xīnqíng bù hǎo.",
      "pinyin_numeric": "jin1tian1 tian1qi4 hen3 re4, wo3 xin1qing2 bu4 hao3.",
      "translation_en": "The weather is very hot today, and I'm in a bad mood.",
      "translation_ko": "오늘 날씨가 매우 더워서 기분이 안 좋아요."
    },
    {
      "text": "下雨天很涼快，心情很舒服。",
      "pinyin": "Xiàyǔ tiān hěn liángkuài, xīnqíng hěn shūfu.",
      "pinyin_numeric": "xia4yu3 tian1 hen3 liang2kuai4, xin1qing2 hen3 shu1fu.",
      "translation_en": "Rainy days are cool, and my mood is very comfortable.",
      "translation_ko": "비 오는 날은 시원해서 기분이 아주 편안해요."
    },
    {
      "text": "颱風天風很大，我有點緊張。",
      "pinyin": "Táifēng tiān fēng hěn dà, wǒ yǒudiǎn jǐnzhāng.",
      "pinyin_numeric": "tai2feng1 tian1 feng1 hen3 da4, wo3 you3dian3 jin3zhang1.",
      "translation_en": "On typhoon days the wind is strong, and I'm a bit nervous.",
      "translation_ko": "태풍이 오는 날은 바람이 많이 불어서 조금 긴장돼요."
    },
    {
      "text": "晴天太陽很大，可是心情很開心。",
      "pinyin": "Qíngtiān tàiyáng hěn dà, kěshì xīnqíng hěn kāixīn.",
      "pinyin_numeric": "qing2tian1 tai4yang2 hen3 da4, ke3shi4 xin1qing2 hen3 kai1xin1.",
      "translation_en": "On sunny days the sun is strong, but my mood is very happy.",
      "translation_ko": "맑은 날은 태양이 강하지만 기분은 아주 즐거워요."
    },
    {
      "text": "陰天很悶熱，我沒有精神。",
      "pinyin": "Yīntiān hěn mēnrè, wǒ méiyǒu jīngshén.",
      "pinyin_numeric": "yin1tian1 hen3 men1re4, wo3 mei2you3 jing1shen2.",
      "translation_en": "Cloudy days are muggy, and I have no energy.",
      "translation_ko": "흐린 날은 후덥지근해서 기운이 없어요."
    },
    {
      "text": "今天溫度三十度，天氣很熱，我很想喝冰水。",
      "pinyin": "Jīntiān wēndù sānshí dù, tiānqì hěn rè, wǒ hěn xiǎng hē bīng shuǐ.",
      "pinyin_numeric": "jin1tian1 wen1du4 san1shi2 du4, tian1qi4 hen3 re4, wo3 hen3 xiang3 he1 bing1 shui3.",
      "translation_en": "Today the temperature is 30 degrees, the weather is very hot, and I really want to drink ice water.",
      "translation_ko": "오늘 기온이 30도라서 날씨가 매우 덥고, 얼음물을 마시고 싶어요."
    },
    {
      "text": "下雨天路很滑，走路要小心。",
      "pinyin": "Xiàyǔ tiān lù hěn huá, zǒulù yào xiǎoxīn.",
      "pinyin_numeric": "xia4yu3 tian1 lu4 hen3 hua2, zou3lu4 yao4 xiao3xin1.",
      "translation_en": "On rainy days the road is slippery, so you need to walk carefully.",
      "translation_ko": "비 오는 날은 길이 미끄러우니까 걸을 때 조심해야 해요."
    },
    {
      "text": "颱風天很危險，我擔心出門。",
      "pinyin": "Táifēng tiān hěn wēixiǎn, wǒ dānxīn chūmén.",
      "pinyin_numeric": "tai2feng1 tian1 hen3 wei1xian3, wo3 dan1xin1 chu1men2.",
      "translation_en": "Typhoon days are very dangerous, and I'm worried about going out.",
      "translation_ko": "태풍이 오는 날은 매우 위험해서 외출이 걱정돼요."
    },
    {
      "text": "天氣很冷的時候，穿外套很舒服。",
      "pinyin": "Tiānqì hěn lěng de shíhou, chuān wàitào hěn shūfu.",
      "pinyin_numeric": "tian1qi4 hen3 leng3 de5 shi2hou4, chuan1 wai4tao4 hen3 shu1fu.",
      "translation_en": "When the weather is very cold, wearing a jacket is comfortable.",
      "translation_ko": "날씨가 매우 추울 때 외투를 입으면 편안해요."
    },
    {
      "text": "今天天氣很舒服，我的心情很好。",
      "pinyin": "Jīntiān tiānqì hěn shūfu, wǒ de xīnqíng hěn hǎo.",
      "pinyin_numeric": "jin1tian1 tian1qi4 hen3 shu1fu, wo3 de5 xin1qing2 hen3 hao3.",
      "translation_en": "The weather is very comfortable today, and my mood is very good.",
      "translation_ko": "오늘 날씨가 아주 쾌적해서 기분이 아주 좋아요."
    }
  ]
}
